import{_ as t,o,c as i,a2 as a}from"./chunks/framework.Bix3-HpO.js";const d=JSON.parse('{"title":"Geo-Targeting","description":"Kemoku Geo-Targeting Features","frontmatter":{"title":"Geo-Targeting","description":"Kemoku Geo-Targeting Features","weight":100,"extra":{"order":100},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/kemoku/geo-targeting"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/kemoku/geo-targeting"}],["meta",{"property":"og:title","content":"Geo-Targeting"}],["meta",{"property":"og:description","content":"Kemoku Geo-Targeting Features"}],["meta",{"name":"twitter:title","content":"Geo-Targeting"}],["meta",{"name":"twitter:description","content":"Kemoku Geo-Targeting Features"}]]},"headers":[],"relativePath":"docs/kemoku/geo-targeting.md","filePath":"docs/kemoku/geo-targeting.md"}'),r={name:"docs/kemoku/geo-targeting.md"};function n(s,e,l,u,c,g){return o(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="geo-targeting" tabindex="-1">Geo-Targeting <a class="header-anchor" href="#geo-targeting" aria-label="Permalink to &quot;Geo-Targeting&quot;">​</a></h1><p><code>💁 since version 2.0</code></p><p>Kemoku includes powerful geo-targeting features that automatically adapt your review content based on your visitors&#39; location. This ensures visitors see relevant operators and get the right affiliate links for their country.</p><hr><h2 id="how-geo-targeting-works" tabindex="-1">How Geo-Targeting Works <a class="header-anchor" href="#how-geo-targeting-works" aria-label="Permalink to &quot;How Geo-Targeting Works&quot;">​</a></h2><p>When a visitor lands on your review page, Kemoku automatically detects their country and shows personalized content:</p><ul><li><strong>Country Support Messages</strong>: Clear indicators showing if the operator accepts players from the visitor&#39;s country</li><li><strong>Smart Affiliate Links</strong>: Automatic routing to the correct affiliate link for the visitor&#39;s location</li><li><strong>Filtered Listings</strong>: Option to hide reviews for operators that don&#39;t accept the visitor&#39;s country</li><li><strong>Fallback Pages</strong>: Redirect visitors from unsupported countries to relevant alternatives</li></ul><hr><h2 id="country-detection" tabindex="-1">Country Detection <a class="header-anchor" href="#country-detection" aria-label="Permalink to &quot;Country Detection&quot;">​</a></h2><p>Kemoku uses multiple methods to detect visitor locations, with automatic fallbacks for maximum accuracy:</p><h3 id="cloudflare-integration" tabindex="-1">Cloudflare Integration <a class="header-anchor" href="#cloudflare-integration" aria-label="Permalink to &quot;Cloudflare Integration&quot;">​</a></h3><p>If you&#39;re using Cloudflare, Kemoku automatically detects visitor countries through Cloudflare&#39;s geo headers. This is the fastest and most accurate method.</p><p><strong>No setup required</strong> - it works automatically when Cloudflare is active.</p><h3 id="maxmind-geolite2" tabindex="-1">MaxMind GeoLite2 <a class="header-anchor" href="#maxmind-geolite2" aria-label="Permalink to &quot;MaxMind GeoLite2&quot;">​</a></h3><p>For sites not using Cloudflare, you can add your free MaxMind license key for professional-grade geo-location.</p><ol><li>Get a free license key from <a href="https://www.maxmind.com/en/geolite2/signup" target="_blank" rel="noreferrer">MaxMind</a></li><li>Go to <strong>Kemoku Reviews</strong> → <strong>Settings</strong> → <strong>Geo Targeting</strong></li><li>Enter your MaxMind license key</li><li>The plugin will automatically download and update the geo database</li></ol><h3 id="intelligent-fallbacks" tabindex="-1">Intelligent Fallbacks <a class="header-anchor" href="#intelligent-fallbacks" aria-label="Permalink to &quot;Intelligent Fallbacks&quot;">​</a></h3><p>If neither Cloudflare nor MaxMind is available, Kemoku uses a default country (US) that you can customize through the <code>kemoku_geo_default_country_code</code> filter:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;?</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">php</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">add_filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">( </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;kemoku_geo_default_country_code&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">( $default ) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;gb&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Return country code</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} );</span></span></code></pre></div><hr><h2 id="geo-targeting-settings" tabindex="-1">Geo-Targeting Settings <a class="header-anchor" href="#geo-targeting-settings" aria-label="Permalink to &quot;Geo-Targeting Settings&quot;">​</a></h2><p>Configure geo-targeting options in <strong>Kemoku Reviews</strong> → <strong>Settings</strong> → <strong>Geo Targeting</strong>.</p><h3 id="country-support-messages" tabindex="-1">Country Support Messages <a class="header-anchor" href="#country-support-messages" aria-label="Permalink to &quot;Country Support Messages&quot;">​</a></h3><p>Customize the messages visitors see based on their country support status:</p><ul><li><strong>Supported Text</strong>: Message when the operator accepts players from the visitor&#39;s country (default: <code>%review% supports players from %country%</code>)</li><li><strong>Unsupported Text</strong>: Message when the operator doesn&#39;t accept players from the visitor&#39;s country (default: <code>%review% does not support players from %country%</code>)</li><li><strong>Bonus Text</strong>: Bonus information shown for supported countries (default: <code>%bonus%</code>)</li><li><strong>Affiliate Link/Button Text</strong>: Text for the affiliate button (default: <code>Claim Now</code>)</li><li><strong>Not Supported Additional Text</strong>: Alternative message for unsupported countries (default: <code>Check out our other reviews for %country% %link%</code>)</li></ul><h3 id="fallback-configuration" tabindex="-1">Fallback Configuration <a class="header-anchor" href="#fallback-configuration" aria-label="Permalink to &quot;Fallback Configuration&quot;">​</a></h3><p>Set up fallback pages for visitors from unsupported countries:</p><ul><li><strong>Page link URL</strong>: Where to redirect visitors when an operator doesn&#39;t accept their country</li><li><strong>Page link text</strong>: Customize the link text (default: your site name)</li></ul><h3 id="maxmind-license-key" tabindex="-1">MaxMind License Key <a class="header-anchor" href="#maxmind-license-key" aria-label="Permalink to &quot;MaxMind License Key&quot;">​</a></h3><p>Enter your MaxMind license key for geo-location when Cloudflare headers are not available.</p><hr><h2 id="review-page-geo-features" tabindex="-1">Review Page Geo Features <a class="header-anchor" href="#review-page-geo-features" aria-label="Permalink to &quot;Review Page Geo Features&quot;">​</a></h2><h3 id="country-support-in-hero-section" tabindex="-1">Country Support in Hero Section <a class="header-anchor" href="#country-support-in-hero-section" aria-label="Permalink to &quot;Country Support in Hero Section&quot;">​</a></h3><p>Enable country support messages in your review hero sections:</p><ol><li>Go to <strong>Kemoku Reviews</strong> → <strong>Settings</strong> → <strong>Hero Section</strong></li><li>Set &quot;Include Geo Section&quot; to &quot;Yes&quot;</li><li>The hero will automatically show country availability with flags and messaging</li></ol><h3 id="country-support-in-info-table" tabindex="-1">Country Support in Info Table <a class="header-anchor" href="#country-support-in-info-table" aria-label="Permalink to &quot;Country Support in Info Table&quot;">​</a></h3><p>Add country support information to your review info tables:</p><ol><li>Edit a review page</li><li>Go to <strong>Review Fields</strong> → <strong>Info Block</strong></li><li>In the &quot;Add country support to Info Table&quot; section, enable the field</li><li>Customize the field name (default: &quot;Support for your country&quot;)</li><li>The info table will include a country support row with availability status</li></ol><h3 id="country-support-block" tabindex="-1">Country Support Block <a class="header-anchor" href="#country-support-block" aria-label="Permalink to &quot;Country Support Block&quot;">​</a></h3><p>Use the dedicated <strong>Review Country Support</strong> block anywhere on your site:</p><ol><li>Add the &quot;Review Country Support&quot; block to any page</li><li>The block automatically shows country availability for the current review</li><li>Perfect for sidebars, comparison pages, or anywhere you want to highlight geo-availability</li></ol><hr><h2 id="listing-geo-features" tabindex="-1">Listing Geo Features <a class="header-anchor" href="#listing-geo-features" aria-label="Permalink to &quot;Listing Geo Features&quot;">​</a></h2><h3 id="country-filtering" tabindex="-1">Country Filtering <a class="header-anchor" href="#country-filtering" aria-label="Permalink to &quot;Country Filtering&quot;">​</a></h3><p>Enable country filtering in your review listings to show only relevant operators:</p><ol><li>Add a <strong>Reviews Table</strong> or <strong>Reviews Grid</strong> block</li><li>In the block settings, enable &quot;Filter by visitor&#39;s country&quot;</li><li>Visitors will only see reviews for operators that accept their country</li></ol><h3 id="country-support-badges" tabindex="-1">Country Support Badges <a class="header-anchor" href="#country-support-badges" aria-label="Permalink to &quot;Country Support Badges&quot;">​</a></h3><p>Show country availability status directly in listing items:</p><ol><li>Add a <strong>Reviews Table</strong> or <strong>Reviews Grid</strong> block</li><li>In the block settings, enable &quot;Show country support badges&quot;</li><li>Each listing item will display a country support indicator</li></ol><hr><h2 id="geo-specific-affiliate-links" tabindex="-1">Geo-Specific Affiliate Links <a class="header-anchor" href="#geo-specific-affiliate-links" aria-label="Permalink to &quot;Geo-Specific Affiliate Links&quot;">​</a></h2><p>Configure different affiliate links for different countries:</p><h3 id="setting-up-geo-links" tabindex="-1">Setting Up Geo Links <a class="header-anchor" href="#setting-up-geo-links" aria-label="Permalink to &quot;Setting Up Geo Links&quot;">​</a></h3><ol><li>Edit a review page</li><li>Go to <strong>Review Fields</strong> → <strong>Geo Targeting</strong></li><li>In the <strong>Affiliate Links</strong> section, add country-specific URLs</li><li>Set a default affiliate link for countries not specifically configured</li></ol><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><ul><li>Visitors from configured countries get the specific affiliate link</li><li>Visitors from other countries get the default affiliate link</li><li>If no default is set, visitors from unconfigured countries see the fallback page</li></ul><hr><h2 id="customization" tabindex="-1">Customization <a class="header-anchor" href="#customization" aria-label="Permalink to &quot;Customization&quot;">​</a></h2><h3 id="custom-geo-messages" tabindex="-1">Custom Geo Messages <a class="header-anchor" href="#custom-geo-messages" aria-label="Permalink to &quot;Custom Geo Messages&quot;">​</a></h3><p>The geo-targeting messages are configured through the plugin settings and cannot be overridden with filters. You can customize these messages in <strong>Kemoku Reviews</strong> → <strong>Settings</strong> → <strong>Geo Targeting</strong>.</p><h3 id="custom-country-names" tabindex="-1">Custom Country Names <a class="header-anchor" href="#custom-country-names" aria-label="Permalink to &quot;Custom Country Names&quot;">​</a></h3><p>For translating or customizing country names, see the <a href="/docs/kemoku/how-to#how-to-changetranslate-country-names">How To Change/Translate Country Names</a> section.</p>`,62)])])}const p=t(r,[["render",n]]);export{d as __pageData,p as default};
